# Plot
fig, axes = plt.subplots(2, 2, figsize=(14, 10))
fig.patch.set_facecolor('#1a1a2e')
COLORS = ['#a78bfa','#f472b6','#60a5fa','#34d399','#fbbf24']

for ax in axes.flat:
    ax.set_facecolor('#252541')
